/**
* OPTIMIZED PROMPT BUILDER (v5.11)
* Includes Dynamic Exercise Library + Consolidated Memory.
*/

const webhookNode = $("Webhook1").first();
if (!webhookNode) throw new Error("Webhook node not found.");

const data = webhookNode.json.body || webhookNode.json || {};

// ── 1. RAW CONTEXT ───────────────────────────────────────────────
const pd           = data.profile || {};
const memories     = data.memories || [];
const assessments  = data.assessments || [];
const activeTasks  = data.recent_tasks_assigned || [];
const messages     = data.messages || [];

const coachPrompt  = data.coach_prompt  || 'You are an empathetic, non-judgmental mental health coach.';
const phasePrompt  = data.phase_prompt  || 'Focus on building therapeutic rapport.';
const pathway      = data.pathway       || 'engagement_rapport_and_assessment';
const theme        = data.dynamic_theme || 'Not yet identified';
const messageCount = data.message_count || 1;
const profileId    = data.profile_id    || '';
const sessionId    = data.session_id    || '';
const isGreeting   = data.is_system_greeting || false;

// ── 2. STRINGIFY CONTEXT SECTIONS ────────────────────────────────
const personalDetails = [
  `Name: ${pd.name || 'Unknown'}`,
  `Age: ${pd.age || 'Unknown'}`,
  `Gender: ${pd.gender || 'Unknown'}`,
  `Concerns: ${Array.isArray(pd.concerns) ? pd.concerns.join(', ') : (pd.concerns || 'Not specified')}`,
].join('\n');

const memoriesStr = memories[0] ? memories[0].memory_text : '  None recorded.';
const assessmentsStr = assessments.map(a => `  ${a.assessment_type}: ${a.score}`).join('\n') || '  None recorded.';
const tasksStr = activeTasks.map(t => `  - ${t.dynamic_title || t.task_name} (${t.task_frequency || 'daily'})`).join('\n') || '  None active.';

const transcript = messages.slice(-15)
  .map(m => `  ${m.role === 'user' ? 'Client' : 'Therapist'}: ${String(m.content || '')}`)
  .join('\n');

// ── 3. PACING / OVERRIDE INSTRUCTION ─────────────────────────────
let pacingInstruction = '';
let shouldRunDiscovery = false;

if (isGreeting) {
  pacingInstruction = `\n[GREETING]\nGreet ${pd.name || 'there'} warmly. Introduce yourself. Reference their concerns. Ensure is_session_close is false.`;
} else if (messageCount >= 15 && messageCount % 5 === 0) {
  pacingInstruction = `\n[SYSTEM] It is turn ${messageCount}. Recommend a clinical pathway now. Set is_session_close to false.`;
  shouldRunDiscovery = true;
}

// ── 4. FINAL ASSEMBLED SYSTEM PROMPT ─────────────────────────────
const systemPrompt = [
  coachPrompt,
  '',
  phasePrompt,
  '',
  '### MEMORY AGENT INSTRUCTIONS (CRITICAL)',
  '1. Maintaining a single consolidated memory block for the client is your priority.',
  '2. When the client reveals a significant, persistent fact, update the memory block.',
  '3. Call "Save Clinical Memory" tool with the NEW consolidated string.',
  'IDs: profile_id="' + profileId + '", source_session_id="' + sessionId + '", memory_type="life_context".',
  '',
  '[CLIENT PROFILE]',
  personalDetails,
  '',
  '[CONSOLIDATED CLINICAL MEMORY]',
  memoriesStr,
  '',
  '[CURRENT CLINICAL THEME]',
  theme,
  '',
  '[DYNAMIC EXERCISE LIBRARY]',
  '- Breathing: box_breathing, 4_7_8_breathing, diaphragmatic_breathing',
  '- Grounding: 5_4_3_2_1_senses, body_scan, progressive_muscle_relaxation',
  '- Meditation: calm_mind, focus_anchor, sleep_wind_down, gratitude_reflection',
  '',
  '### EXERCISE TRIGGER INSTRUCTIONS',
  'If the client is experiencing acute anxiety, panic, or intense stress, you SHOULD suggest a relevant exercise.',
  'To trigger it, set "dynamic_in_chat_exercise" to the EXERCISE_ID (e.g., "box_breathing"). Use NULL if no exercise is triggered.',
  '',
  '[SESSION TRANSCRIPT (last 15 messages)]',
  transcript,
  '',
  pacingInstruction,
  '',
  '### OUTPUT FORMAT',
  'Your FINAL response MUST be a JSON object with at least these fields:',
  '- "reply": A single conversational paragraph ending in a reflection/question.',
  '- "is_session_close": boolean.',
  '- "dynamic_in_chat_exercise": ID from catalog or null.',
  '- "dynamic_content": object containing type and payload (ONLY if exercise triggered).',
  // Add this inside your systemPrompt array in Prompt Builder2
'### OPERATIONAL PROTOCOL',
'1. STEP 1: Analyze the client message for new significant life facts.',
'2. STEP 2: If a fact is found, CALL the "Save Clinical Memory" tool.',
'3. STEP 3: ONLY AFTER the tool completes, generate your final JSON response.',
].join('\n');

return [{ json: { systemPrompt, userMessage: data.message_text || '', profileId, sessionId, shouldRunDiscovery, messageCount } }];

