{
  "type": "object",
  "properties": {
    "reply": {
      "type": "string",
      "description": "A single conversational paragraph that builds rapport and ends with a gentle question or reflection."
    },
    "is_session_close": {
      "type": "boolean",
      "description": "Whether the session should end now."
    },
    "dynamic_in_chat_exercise": {
      "type": "string",
      "description": "The ID of the clinical exercise to trigger (e.g., 'box_breathing'), or null if none.",
      "nullable": true
    },
    "dynamic_content": {
      "type": "object",
      "properties": {
        "type": { "type": "string", "enum": ["exercise"] },
        "payload": { "type": "string" }
      },
      "description": "Optional object for frontend trigger logic."
    }
  },
  "required": ["reply", "is_session_close", "dynamic_in_chat_exercise"]
}

