/**
* IDEAL RESPONSE FORMATTER (v5.10)
* Guaranteed dynamic_in_chat_exercise presence + Discovery integration.
*/

const webhookNode = $("Webhook1").first();
const therapistNode = $("Therapist Agent1").first();
if (!therapistNode) throw new Error("Therapist Agent output not found.");

const data = webhookNode.json.body || webhookNode.json || {};
const rawOutput = therapistNode.json.output;
let therapistOutput = {};

if (typeof rawOutput === 'object' && rawOutput !== null) {
  therapistOutput = rawOutput;
} else if (typeof rawOutput === 'string') {
  therapistOutput = { reply: rawOutput };
}

// 1. Build Base Response
const finalResponse = {
  reply: therapistOutput.reply || (typeof rawOutput === 'string' ? rawOutput : ''),
  session_state: data.session_state || 'active',
  pathway: data.pathway || 'engagement_rapport_and_assessment',
  is_session_close: therapistOutput.is_session_close || false,
  dynamic_in_chat_exercise: therapistOutput.dynamic_in_chat_exercise || therapistOutput.dynamic_content?.payload || null,
  guardrail_status: 'passed',
  crisis_detected: false
};

// 2. Map Dynamic Content Object (Optional)
if (therapistOutput.dynamic_content) {
  finalResponse.dynamic_content = therapistOutput.dynamic_content;
}

// 3. Discovery Agent Integration
try {
  const discoveryNode = $("Discovery Agent1").first();
  if (discoveryNode && discoveryNode.json.output) {
    const disc = discoveryNode.json.output;
    finalResponse.dynamic_theme      = disc.dynamic_theme;
    finalResponse.suggested_pathway  = disc.suggested_pathway;
    finalResponse.pathway_confidence = disc.pathway_confidence;
  }
} catch (e) {
  // Discovery not run
}

return [{ json: finalResponse }];
